// Verify an encoded ledger string against its embedded checksum.
function verify(encoded) {
  const parts = String(encoded).split("|");
  if (parts.length !== 3) return false;
  const id = Number(parts[0]);
  const amountCents = Number(parts[1]);
  const cc = parts[2];
  if (!Number.isFinite(id) || !Number.isFinite(amountCents)) return false;
  const expected = String((id + amountCents) % 97).padStart(2, "0");
  return cc === expected;
}
module.exports = { verify };
